from dataclasses import dataclass
from typing import Callable

@dataclass(frozen=True)
class State:
    data: tuple  # immutable snapshot of world state

@dataclass
class Action:
    name: str
    precondition: Callable[[State], bool]
    effect: Callable[[State], State]

class UtilityBasedAgent:
    def __init__(
        self,
        actions: list[Action],
        utility_fn: Callable[[State], float],
    ):
        self.actions = actions
        self.utility = utility_fn

    def act(self, current_state: State) -> str | None:
        best_action = None
        best_utility = float("-inf")
        for action in self.actions:
            if not action.precondition(current_state):
                continue
            next_state = action.effect(current_state)
            u = self.utility(next_state)
            if u > best_utility:
                best_utility = u
                best_action = action.name
        return best_action

# Unlike goal-based: no search tree, no BFS
# Each action is scored once; O(actions) selection

# Utility-based agent with one-step lookahead
# Scores each action by the utility of the NEXT state it produces
from dataclasses import dataclass
from typing import Callable

@dataclass(frozen=True)
class State:
    data: tuple

@dataclass
class Action:
    name: str
    precondition: Callable
    effect: Callable

def greedy_utility_agent(state: State, actions: list[Action],
                          utility: Callable[[State], float]) -> str | None:
    """One-step lookahead: pick action with best immediate next-state utility."""
    best, best_u = None, float("-inf")
    for a in actions:
        if a.precondition(state):
            u = utility(a.effect(state))
            if u > best_u:
                best_u, best = u, a.name
    return best

def multi_step_utility_agent(state: State, actions: list[Action],
                              utility: Callable[[State], float],
                              depth: int = 3) -> str | None:
    """Minimax-style: look N steps ahead and pick action leading to best leaf utility."""
    def search(s: State, d: int) -> float:
        if d == 0:
            return utility(s)
        available = [a for a in actions if a.precondition(s)]
        if not available:
            return utility(s)
        return max(search(a.effect(s), d - 1) for a in available)

    best, best_u = None, float("-inf")
    for a in actions:
        if a.precondition(state):
            u = search(a.effect(state), depth - 1)
            if u > best_u:
                best_u, best = u, a.name
    return best

# One-step greedy: fast, O(actions); may take locally-good but globally-bad moves
# Multi-step: exponential in depth; dramatically better in adversarial / trap-heavy domains
